#!/usr/bin/env python3
import sys, base64, urllib.request, urllib.error, json

REPO = "ADEILSONTAVARES/gitnanu-ssot-public"
BRANCH = "main"

def github_put(token, path, b64content, message):
    url = f"https://api.github.com/repos/{REPO}/contents/{path}"
    headers = {"Authorization": f"token {token}", "Accept": "application/vnd.github.v3+json"}
    sha = None
    try:
        with urllib.request.urlopen(urllib.request.Request(url, headers=headers)) as r:
            sha = json.loads(r.read())["sha"]
    except urllib.error.HTTPError as e:
        if e.code != 404: raise
    data = {"message": message, "content": b64content, "branch": BRANCH}
    if sha: data["sha"] = sha
    req = urllib.request.Request(url, data=json.dumps(data).encode(), method="PUT",
        headers={**headers, "Content-Type": "application/json"})
    try:
        with urllib.request.urlopen(req) as r:
            return True, r.status
    except urllib.error.HTTPError as e:
        return False, f"{e.code}: {e.read().decode()[:200]}"

FILES = {
    'ssot/addons/dores_por_studio/S01/DORES_S01_doc_assistant_v1.yaml': '',
    'ssot/addons/dores_por_studio/S01/DORES_S01_presentation_ai_v1.yaml': '',
    'ssot/addons/dores_por_studio/S02/DORES_S02_ide_2x1_v1.yaml': '',
    'ssot/addons/dores_por_studio/S04/DORES_S04_adobe_firefly_v1.yaml': '',
    'ssot/addons/dores_por_studio/S04/DORES_S04_ideogram_ai_v1.yaml': '',
    'ssot/addons/dores_por_studio/S04/DORES_S04_recraft_v3_v1.yaml': '',

}

def main():
    if len(sys.argv) < 2:
        print("Uso: python3 deploy_lote_v.py <TOKEN>")
        sys.exit(1)
    token = sys.argv[1]
    print(f"Deploy Lote V — {len(FILES)} dores (S01/S02/S04)")
    for p in FILES: print(f"  {p.split('/')[-1]}")
    print("=" * 60)
    ok = err = 0
    for path, b64 in FILES.items():
        fname = path.split("/")[-1]
        success, status = github_put(token, path, b64, f"feat(lote-v): {fname}")
        if success:
            print(f"  [ok] {fname}")
            ok += 1
        else:
            print(f"  [ERRO] {fname}: {status}")
            err += 1
    print("=" * 60)
    print(f"Resultado: {ok} OK | {err} ERRO")
    if err == 0:
        print("\nDEPLOY COMPLETO! Rode na VPS: git pull && python3 scripts/gate_pass_strict.py 2>&1 | tail -3")

if __name__ == "__main__":
    main()
